import { Capacitor } from "@capacitor/core";
import { App as CapacitorApp } from "@capacitor/app";
import { Browser } from "@capacitor/browser";
import { container } from "../utils/container";
import type { AuthSignInLifecycle } from "./ports/AuthSignInLifecycle";
import { parseOAuthCallbackCode } from "./parseOAuthCallbackCode";
import { getSupabaseClient } from "./supabaseClient";

const NATIVE_REDIRECT_URL = "todoquest://auth/callback";

export interface GoogleSignInStrategy {
  init(): void;
  signIn(): Promise<void>;
}

class WebGoogleSignInStrategy implements GoogleSignInStrategy {
  init(): void {
    // no-op: web flow needs no deep-link listener
  }

  async signIn(): Promise<void> {
    await getSupabaseClient().auth.signInWithOAuth({
      provider: "google",
      options: {
        redirectTo: window.location.origin + window.location.pathname,
      },
    });
  }
}

class NativeGoogleSignInStrategy implements GoogleSignInStrategy {
  private readonly handledOAuthCodes = new Set<string>();

  constructor(private readonly lifecycle: AuthSignInLifecycle) {}

  init(): void {
    CapacitorApp.addListener("appUrlOpen", ({ url }) => {
      void this.handleOAuthCallback(url);
    });

    void CapacitorApp.getLaunchUrl().then((launch) => {
      if (launch?.url) void this.handleOAuthCallback(launch.url);
    });
  }

  async signIn(): Promise<void> {
    const { data, error } = await getSupabaseClient().auth.signInWithOAuth({
      provider: "google",
      options: { redirectTo: NATIVE_REDIRECT_URL, skipBrowserRedirect: true },
    });

    if (error || !data.url) {
      throw error ?? new Error("No OAuth URL returned");
    }

    await Browser.open({ url: data.url });
  }

  private async handleOAuthCallback(url: string): Promise<void> {
    const code = parseOAuthCallbackCode(url, NATIVE_REDIRECT_URL);
    if (!code) return;
    if (this.handledOAuthCodes.has(code)) return;
    this.handledOAuthCodes.add(code);

    this.lifecycle.notifySignInResolving();

    const { error } = await getSupabaseClient().auth.exchangeCodeForSession(code);
    if (error) {
      this.lifecycle.notifySignInFailed();
      return;
    }

    await Browser.close();
  }
}

class DevGoogleSignInStrategy implements GoogleSignInStrategy {
  init(): void {}

  async signIn(): Promise<void> {
    // Dev mode auto-signs in via DevAuthSessionProvider.
  }
}

export function createGoogleSignInStrategy(
  lifecycle: AuthSignInLifecycle
): GoogleSignInStrategy {
  if (container.resolve("config").devMode) {
    return new DevGoogleSignInStrategy();
  }

  return Capacitor.isNativePlatform()
    ? new NativeGoogleSignInStrategy(lifecycle)
    : new WebGoogleSignInStrategy();
}
