import type {
  AuthSession,
  IAuthSessionProvider,
} from "./ports/IAuthSessionProvider";

const DEV_TOKEN = "dev";
const DEV_EMAIL = "dev@local.test";

export class DevAuthSessionProvider implements IAuthSessionProvider {
  private session: AuthSession = {
    accessToken: DEV_TOKEN,
    email: DEV_EMAIL,
  };

  initialize(onSessionChange: (session: AuthSession | null) => void): void {
    onSessionChange(this.session);
  }

  async getAccessToken(): Promise<string | null> {
    return this.session.accessToken;
  }

  async signInWithGoogle(): Promise<void> {
    // Dev mode is always signed in.
  }

  async signOut(): Promise<void> {
    // Dev mode keeps the session for local work.
  }
}

export { DEV_EMAIL, DEV_TOKEN };
