import { SingletonContainer } from "singleton-injection";
import { Config } from "../config/Config";
import { GoalRepo } from "../persistence/GoalRepo";
import { TaskRepo } from "../persistence/TaskRepo";
import type { IConfig } from "../core/ports/IConfig";
import type { IGoalRepo } from "../core/ports/IGoalRepo";
import type { ITaskRepo } from "../core/ports/ITaskRepo";
import { MenuController } from "../view/view-controllers/MenuController";
import { CreateGoalController } from "../view/view-controllers/CreateGoalController";
import { EditGoalController } from "../view/view-controllers/EditGoalController";
import { ListGoalsController } from "../view/view-controllers/ListGoalsController";
import { DeleteGoalController } from "../view/view-controllers/DeleteGoalController";
import { ListTasksController } from "../view/view-controllers/ListTasksController";
import { CreateTaskController } from "../view/view-controllers/CreateTaskController";
import { DeleteTaskController } from "../view/view-controllers/DeleteTaskController";
import { ToggleTaskController } from "../view/view-controllers/ToggleTaskController";
import { EditTaskController } from "../view/view-controllers/EditTaskController";
import { AuthController } from "../auth/AuthController";
import { createAuthSessionProvider } from "../auth/createAuthSessionProvider";
import { AuthenticatedHttpClient } from "../persistence/AuthenticatedHttpClient";
import type { IAuthenticatedHttpClient } from "../persistence/ports/IAuthenticatedHttpClient";

const singletonMap = {
  config: (): IConfig => new Config(),
  authController: (): AuthController => new AuthController(),
  authenticatedHttpClient: (): IAuthenticatedHttpClient =>
    new AuthenticatedHttpClient(createAuthSessionProvider(), {
      handleUnauthorized: () =>
        container.resolve("authController").handleUnauthorized(),
    }),
  goalRepo: (): IGoalRepo => new GoalRepo(),
  taskRepo: (): ITaskRepo => new TaskRepo(),
  menuController: (): MenuController => new MenuController(),
  createGoalController: (): CreateGoalController => new CreateGoalController(),
  editGoalController: (): EditGoalController => new EditGoalController(),
  listGoalsController: (): ListGoalsController => new ListGoalsController(),
  deleteGoalController: (): DeleteGoalController => new DeleteGoalController(),
  listTasksController: (): ListTasksController => new ListTasksController(),
  createTaskController: (): CreateTaskController => new CreateTaskController(),
  deleteTaskController: (): DeleteTaskController => new DeleteTaskController(),
  toggleTaskController: (): ToggleTaskController => new ToggleTaskController(),
  editTaskController: (): EditTaskController => new EditTaskController(),
};

export const container = new SingletonContainer(singletonMap);
