import type { Task } from "../core/entities/Task";
import type { ITaskRepo } from "../core/ports/ITaskRepo";
import {
  CreateTaskError,
  DeleteTaskError,
  LoadTasksError,
  ToggleTaskError,
  UpdateTaskError,
} from "../core/errors/task-errors";
import { container } from "../utils/container";

class TaskRepo implements ITaskRepo {
  async getTasks(goalId: string): Promise<Task[] | LoadTasksError> {
    try {
      const res = await container.resolve("authenticatedHttpClient").fetch(
        `${container.resolve("config").apiUrl}/api/goals/${goalId}/tasks`
      );
      if (!res.ok) {
        return new LoadTasksError("Failed to load tasks");
      }
      const data = (await res.json()) as { tasks: Task[] };
      return data.tasks;
    } catch {
      return new LoadTasksError("Failed to load tasks");
    }
  }

  async createTask(
    input: Pick<Task, "goalId" | "name">
  ): Promise<Task | CreateTaskError> {
    try {
      const res = await container.resolve("authenticatedHttpClient").fetch(
        `${container.resolve("config").apiUrl}/api/goals/${input.goalId}/tasks`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ name: input.name }),
        }
      );
      if (!res.ok) {
        return new CreateTaskError("Failed to create task");
      }
      return (await res.json()) as Task;
    } catch {
      return new CreateTaskError("Failed to create task");
    }
  }

  async deleteTask(id: string): Promise<void | DeleteTaskError> {
    try {
      const res = await container.resolve("authenticatedHttpClient").fetch(
        `${container.resolve("config").apiUrl}/api/tasks/${id}`,
        {
          method: "DELETE",
        }
      );
      if (!res.ok) {
        return new DeleteTaskError("Failed to delete task");
      }
    } catch {
      return new DeleteTaskError("Failed to delete task");
    }
  }

  async toggleTask(
    id: string,
    completed: boolean
  ): Promise<void | ToggleTaskError> {
    try {
      const res = await container.resolve("authenticatedHttpClient").fetch(
        `${container.resolve("config").apiUrl}/api/tasks/${id}`,
        {
          method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ completed }),
      });
      if (!res.ok) {
        return new ToggleTaskError("Failed to update task");
      }
    } catch {
      return new ToggleTaskError("Failed to update task");
    }
  }

  async updateTaskName(
    id: string,
    name: string
  ): Promise<void | UpdateTaskError> {
    try {
      const res = await container.resolve("authenticatedHttpClient").fetch(
        `${container.resolve("config").apiUrl}/api/tasks/${id}`,
        {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ name }),
        }
      );
      if (!res.ok) {
        return new UpdateTaskError("Failed to update task");
      }
    } catch {
      return new UpdateTaskError("Failed to update task");
    }
  }
}
export { TaskRepo };
