import { useState } from "react";
import { AlertDialog, Accordion } from "radix-ui";
import { ChevronDownIcon, Pencil1Icon, ReloadIcon, TrashIcon } from "@radix-ui/react-icons";
import type { Goal } from "../../../../core/entities/Goal";
import type { ListTasksController } from "../../../view-controllers/ListTasksController";
import dialogClasses from "../../components/dialog/dialog.module.css";
import buttonClasses from "../../components/button/button.module.css";
import { useControllerState } from "../../hooks/useControllerState";
import classes from "./goals.module.css";
import { TaskList } from "./TaskList";

interface Props {
  goals: Goal[];
  listTasksController: ListTasksController;
  onDeleteGoal: (goalId: string) => Promise<void | Error>;
  onEditGoal: (goal: Goal) => void;
  onAddTask: (goalId: string, name: string) => Promise<void | Error>;
}

export function GoalsList({
  goals,
  listTasksController,
  onDeleteGoal,
  onEditGoal,
  onAddTask,
}: Props) {
  const { tasksByGoalId } = useControllerState(listTasksController);

  const [pendingDelete, setPendingDelete] = useState<Goal | null>(null);
  const [deletingIds, setDeletingIds] = useState<Set<string>>(new Set());
  const [expandedGoalId, setExpandedGoalId] = useState<string>("");

  function handleOpenChange(open: boolean) {
    if (!open) {
      setPendingDelete(null);
    }
  }

  function handleExpandedChange(value: string) {
    setExpandedGoalId(value);

    if (value && !(value in tasksByGoalId)) {
      void listTasksController.loadTasks(value);
    }
  }

  async function handleConfirmDelete() {
    if (!pendingDelete) {
      return;
    }

    const goalId = pendingDelete.id;
    setPendingDelete(null);
    setDeletingIds((prev) => new Set(prev).add(goalId));

    await onDeleteGoal(goalId);

    setDeletingIds((prev) => {
      const next = new Set(prev);
      next.delete(goalId);
      return next;
    });
  }

  return (
    <div className={classes.GoalsList}>
      <p className={classes.GoalsTitle}>Active Quests</p>
      {goals.length === 0 ? (
        <p className={classes.Empty}>No quests yet. Create your first goal!</p>
      ) : (
        <Accordion.Root
          type="single"
          collapsible
          className={classes.List}
          value={expandedGoalId}
          onValueChange={handleExpandedChange}
        >
          {goals.map((goal) => {
            const isDeleting = deletingIds.has(goal.id);
            const tasks = tasksByGoalId[goal.id];
            const totalCount = tasks?.length ?? goal.totalTasks ?? 0;
            const completedCount = tasks
              ? tasks.filter((task) => task.completed).length
              : goal.completedTasks ?? 0;
            const progressPercent =
              totalCount > 0 ? (completedCount / totalCount) * 100 : 0;

            return (
              <Accordion.Item
                key={goal.id}
                value={goal.id}
                className={
                  isDeleting
                    ? `${classes.GoalItem} ${classes.GoalItemDeleting}`
                    : classes.GoalItem
                }
              >
                <div className={classes.GoalHeader}>
                  <Accordion.Trigger className={classes.GoalTrigger}>
                    <ChevronDownIcon className={classes.Chevron} />
                    <span className={classes.GoalName}>{goal.name}</span>
                    {totalCount > 0 && (
                      <span className={classes.ProgressBadge}>
                        {completedCount}/{totalCount}
                      </span>
                    )}
                  </Accordion.Trigger>
                  <button
                    type="button"
                    aria-label="Edit goal"
                    className={classes.HeaderActionButton}
                    disabled={isDeleting}
                    onClick={(event) => {
                      event.stopPropagation();
                      onEditGoal(goal);
                    }}
                  >
                    <Pencil1Icon />
                  </button>
                  <button
                    type="button"
                    aria-label="Delete goal"
                    className={classes.HeaderActionButton}
                    disabled={isDeleting}
                    onClick={() => setPendingDelete(goal)}
                  >
                    {isDeleting ? (
                      <ReloadIcon className={classes.Spinning} />
                    ) : (
                      <TrashIcon />
                    )}
                  </button>
                </div>
                {totalCount > 0 && (
                  <div className={classes.ProgressBarTrack}>
                    <div
                      className={classes.ProgressBarFill}
                      style={{ width: `${progressPercent}%` }}
                    />
                  </div>
                )}
                <Accordion.Content className={classes.AccordionContent}>
                  <TaskList
                    goalId={goal.id}
                    listTasksController={listTasksController}
                    onAddTask={onAddTask}
                  />
                </Accordion.Content>
              </Accordion.Item>
            );
          })}
        </Accordion.Root>
      )}
      <AlertDialog.Root
        open={pendingDelete !== null}
        onOpenChange={handleOpenChange}
      >
        <AlertDialog.Portal>
          <AlertDialog.Overlay className={dialogClasses.DialogOverlay}>
            <AlertDialog.Content className={dialogClasses.DialogContent}>
              <AlertDialog.Title className={dialogClasses.DialogTitle}>
                Delete goal
              </AlertDialog.Title>
              <AlertDialog.Description
                className={dialogClasses.DialogDescription}
              >
                Are you sure you want to delete "{pendingDelete?.name}"? This
                cannot be undone.
              </AlertDialog.Description>
              <div className={classes.DialogActions}>
                <AlertDialog.Cancel asChild>
                  <button type="button" className={buttonClasses.Button}>
                    Cancel
                  </button>
                </AlertDialog.Cancel>
                <AlertDialog.Action asChild>
                  <button
                    type="button"
                    className={buttonClasses.Button}
                    onClick={handleConfirmDelete}
                  >
                    Delete
                  </button>
                </AlertDialog.Action>
              </div>
            </AlertDialog.Content>
          </AlertDialog.Overlay>
        </AlertDialog.Portal>
      </AlertDialog.Root>
    </div>
  );
}
