import type { UpdateTaskError } from "../../core/errors/task-errors";
import { container } from "../../utils/container";

class EditTaskController {
  handleEditTask(
    taskId: string,
    name: string
  ): Promise<void | UpdateTaskError> {
    const taskRepo = container.resolve("taskRepo");
    return taskRepo.updateTaskName(taskId, name);
  }
}

export { EditTaskController };
