import { container } from "../utils/container";
import { DevAuthSessionProvider } from "./DevAuthSessionProvider";
import type { IAuthSessionProvider } from "./ports/IAuthSessionProvider";
import { SupabaseAuthSessionProvider } from "./SupabaseAuthSessionProvider";

export function createAuthSessionProvider(): IAuthSessionProvider {
  return container.resolve("config").devMode
    ? new DevAuthSessionProvider()
    : new SupabaseAuthSessionProvider();
}
