import type { IConfig } from "../core/ports/IConfig";

const DEFAULTS = {
  apiUrl:
    "https://n5tiujndiheepocx3f63fsxzcy0kmvgj.lambda-url.ap-south-1.on.aws",
  supabaseUrl: "",
  supabasePublishableKey: "",
} as const;

function readString(read: () => string | undefined, fallback: string): string {
  try {
    const value = read();
    return value !== undefined && value !== "" ? value : fallback;
  } catch {
    return fallback;
  }
}

function readBool(read: () => string | undefined, fallback: boolean): boolean {
  try {
    const value = read();
    if (value === undefined) return fallback;
    return value === "true";
  } catch {
    return fallback;
  }
}

function readIsProduction(): boolean {
  try {
    return process.env.NODE_ENV === "production";
  } catch {
    return true;
  }
}

function readDevMode(): boolean {
  try {
    return process.env.NODE_ENV === "development";
  } catch {
    return false;
  }
}

export class Config implements IConfig {
  readonly apiUrl: string;
  readonly devMode: boolean;
  readonly useMockApi: boolean;
  readonly supabaseUrl: string;
  readonly supabasePublishableKey: string;
  readonly isProduction: boolean;

  constructor() {
    this.apiUrl = readString(
      () => process.env.BUN_PUBLIC_API_URL,
      DEFAULTS.apiUrl
    );
    this.devMode = readDevMode();
    this.useMockApi = readBool(() => process.env.BUN_PUBLIC_USE_MOCK_API, true);
    this.supabaseUrl = readString(
      () => process.env.BUN_PUBLIC_SUPABASE_URL,
      DEFAULTS.supabaseUrl
    );
    this.supabasePublishableKey = readString(
      () => process.env.BUN_PUBLIC_SUPABASE_PUBLISHABLE_KEY,
      DEFAULTS.supabasePublishableKey
    );
    this.isProduction = readIsProduction();
  }
}
