import type { UpdateGoalError } from "../../core/errors/goal-errors";
import { Subject, type Observable } from "../../libs/rx";
import { container } from "../../utils/container";

class EditGoalController {
  handleEditGoal(
    goalId: string,
    name: string
  ): Promise<void | UpdateGoalError> {
    const goalRepo = container.resolve("goalRepo");
    return goalRepo.updateGoal(goalId, name);
  }

  handleCancelEditGoal(): void {
    this._cancelEditGoal.next();
  }

  private _cancelEditGoal = new Subject<void>();

  get cancelEditGoal$(): Observable<void> {
    return this._cancelEditGoal.asObservable();
  }
}

export { EditGoalController };
