import type { IUnauthorizedHandler } from "../auth/ports/IUnauthorizedHandler";
import type { IAuthSessionProvider } from "../auth/ports/IAuthSessionProvider";
import type { IAuthenticatedHttpClient } from "./ports/IAuthenticatedHttpClient";

class AuthenticatedHttpClient implements IAuthenticatedHttpClient {
  private signingOut = false;

  constructor(
    private readonly sessionProvider: IAuthSessionProvider,
    private readonly unauthorizedHandler: IUnauthorizedHandler
  ) {}

  async fetch(input: string, init: RequestInit = {}): Promise<Response> {
    const accessToken = await this.sessionProvider.getAccessToken();

    const headers = new Headers(init.headers);
    if (accessToken) {
      headers.set("Authorization", `Bearer ${accessToken}`);
    }

    const response = await fetch(input, { ...init, headers });

    if (response.status === 401) {
      void this.handleUnauthorized();
    }

    return response;
  }

  private async handleUnauthorized(): Promise<void> {
    if (this.signingOut) return;
    this.signingOut = true;

    try {
      await this.unauthorizedHandler.handleUnauthorized();
    } finally {
      this.signingOut = false;
    }
  }
}

export { AuthenticatedHttpClient };
