import { BehaviorSubject, Observable, take } from "../../libs/rx";
import { container } from "../../utils/container";

interface State {
  showCreateGoalForm: boolean;
  editingGoalId: string | null;
}

const initialState: State = {
  showCreateGoalForm: false,
  editingGoalId: null,
};

class MenuController {
  private _state = new BehaviorSubject<State>(initialState);

  handleCreateGoal() {
    this.patchState({
      showCreateGoalForm: true,
    });

    const createGoalController = container.resolve("createGoalController");

    createGoalController.cancelCreateGoal$.pipe(take(1)).subscribe(() => {
      this.patchState({
        showCreateGoalForm: false,
      });
    });
  }

  handleEditGoal(goalId: string) {
    this.patchState({
      editingGoalId: goalId,
    });

    const editGoalController = container.resolve("editGoalController");

    editGoalController.cancelEditGoal$.pipe(take(1)).subscribe(() => {
      this.patchState({
        editingGoalId: null,
      });
    });
  }

  private patchState(newState: Partial<State>) {
    this._state.next({
      ...this._state.value,
      ...newState,
    });
  }

  get state$(): Observable<State> {
    return this._state.asObservable();
  }
  getState(): State {
    return this._state.value;
  }
}

export { MenuController };
