import type { Task } from "../../core/entities/Task";
import { LoadTasksError } from "../../core/errors/task-errors";
import { BehaviorSubject } from "../../libs/rx";
import { container } from "../../utils/container";

interface PendingRename {
  goalId: string;
  name: string;
}

interface State {
  tasksByGoalId: Record<string, Task[]>;
  savingIds: Set<string>;
  pendingIds: Set<string>;
}

const initialState: State = {
  tasksByGoalId: {},
  savingIds: new Set(),
  pendingIds: new Set(),
};

const RENAME_DEBOUNCE_MS = 400;

class ListTasksController {
  async loadTasks(goalId: string): Promise<void | LoadTasksError> {
    const taskRepo = container.resolve("taskRepo");
    const tasksResult = await taskRepo.getTasks(goalId);

    if (tasksResult instanceof LoadTasksError) {
      return tasksResult;
    }

    this._state.next({
      ...this._state.value,
      tasksByGoalId: {
        ...this._state.value.tasksByGoalId,
        [goalId]: tasksResult as Task[],
      },
    });
  }

  addTask(goalId: string, task: Task): void {
    const existingTasks = this._state.value.tasksByGoalId[goalId] ?? [];

    this._state.next({
      ...this._state.value,
      tasksByGoalId: {
        ...this._state.value.tasksByGoalId,
        [goalId]: [...existingTasks, task],
      },
    });
  }

  removeTask(goalId: string, taskId: string): void {
    const existingTasks = this._state.value.tasksByGoalId[goalId] ?? [];

    this._state.next({
      ...this._state.value,
      tasksByGoalId: {
        ...this._state.value.tasksByGoalId,
        [goalId]: existingTasks.filter((task) => task.id !== taskId),
      },
    });
  }

  setTaskCompleted(goalId: string, taskId: string, completed: boolean): void {
    const existingTasks = this._state.value.tasksByGoalId[goalId] ?? [];

    this._state.next({
      ...this._state.value,
      tasksByGoalId: {
        ...this._state.value.tasksByGoalId,
        [goalId]: existingTasks.map((task) =>
          task.id === taskId ? { ...task, completed } : task
        ),
      },
    });
  }

  updateTaskName(goalId: string, taskId: string, name: string): void {
    const existingTasks = this._state.value.tasksByGoalId[goalId] ?? [];

    this._state.next({
      ...this._state.value,
      tasksByGoalId: {
        ...this._state.value.tasksByGoalId,
        [goalId]: existingTasks.map((task) =>
          task.id === taskId ? { ...task, name } : task
        ),
      },
    });
  }

  scheduleTaskRename(goalId: string, taskId: string, name: string): void {
    this._pendingRenames.set(taskId, { goalId, name });

    const existingTimer = this._renameTimers.get(taskId);
    if (existingTimer !== undefined) {
      clearTimeout(existingTimer);
    }

    this._renameTimers.set(
      taskId,
      setTimeout(() => {
        void this.persistTaskRename(taskId);
      }, RENAME_DEBOUNCE_MS)
    );
  }

  flushTaskRename(taskId: string): void {
    const existingTimer = this._renameTimers.get(taskId);
    if (existingTimer !== undefined) {
      clearTimeout(existingTimer);
      this._renameTimers.delete(taskId);
    }

    void this.persistTaskRename(taskId);
  }

  cancelTaskRename(taskId: string): void {
    const existingTimer = this._renameTimers.get(taskId);
    if (existingTimer !== undefined) {
      clearTimeout(existingTimer);
      this._renameTimers.delete(taskId);
    }

    this._pendingRenames.delete(taskId);
  }

  async toggleTask(
    goalId: string,
    taskId: string,
    completed: boolean
  ): Promise<void> {
    this.addPending(taskId);

    try {
      const toggleTaskController = container.resolve("toggleTaskController");
      const result = await toggleTaskController.handleToggleTask(
        taskId,
        completed
      );

      if (!(result instanceof Error)) {
        this.setTaskCompleted(goalId, taskId, completed);
      }
    } finally {
      this.removePending(taskId);
    }
  }

  async deleteTask(goalId: string, taskId: string): Promise<void> {
    this.addPending(taskId);

    try {
      const deleteTaskController = container.resolve("deleteTaskController");
      const result = await deleteTaskController.handleDeleteTask(taskId);

      if (!(result instanceof Error)) {
        this.removeTask(goalId, taskId);
      }
    } finally {
      this.removePending(taskId);
    }
  }

  private async persistTaskRename(taskId: string): Promise<void> {
    this._renameTimers.delete(taskId);

    const pending = this._pendingRenames.get(taskId);
    if (!pending) {
      return;
    }

    this._pendingRenames.delete(taskId);

    const trimmedName = pending.name.trim();
    if (!trimmedName) {
      return;
    }

    const currentName = this.findTaskName(pending.goalId, taskId);
    if (currentName === trimmedName) {
      return;
    }

    this.addSaving(taskId);
    this.updateTaskName(pending.goalId, taskId, trimmedName);

    try {
      const editTaskController = container.resolve("editTaskController");
      await editTaskController.handleEditTask(taskId, trimmedName);
    } finally {
      this.removeSaving(taskId);
    }
  }

  private findTaskName(goalId: string, taskId: string): string | undefined {
    const tasks = this._state.value.tasksByGoalId[goalId] ?? [];
    return tasks.find((task) => task.id === taskId)?.name;
  }

  private addPending(taskId: string): void {
    this._state.next({
      ...this._state.value,
      pendingIds: new Set(this._state.value.pendingIds).add(taskId),
    });
  }

  private removePending(taskId: string): void {
    const pendingIds = new Set(this._state.value.pendingIds);
    pendingIds.delete(taskId);

    this._state.next({
      ...this._state.value,
      pendingIds,
    });
  }

  private addSaving(taskId: string): void {
    this._state.next({
      ...this._state.value,
      savingIds: new Set(this._state.value.savingIds).add(taskId),
    });
  }

  private removeSaving(taskId: string): void {
    const savingIds = new Set(this._state.value.savingIds);
    savingIds.delete(taskId);

    this._state.next({
      ...this._state.value,
      savingIds,
    });
  }

  private _renameTimers = new Map<string, ReturnType<typeof setTimeout>>();
  private _pendingRenames = new Map<string, PendingRename>();
  private _state = new BehaviorSubject<State>(initialState);

  get state$() {
    return this._state.asObservable();
  }

  getState(): State {
    return this._state.value;
  }
}

export { ListTasksController };
