import type { Goal } from "../core/entities/Goal";
import type { IGoalRepo } from "../core/ports/IGoalRepo";
import {
  CreateGoalError,
  DeleteGoalError,
  LoadGoalsError,
  UpdateGoalError,
} from "../core/errors/goal-errors";
import { container } from "../utils/container";

class GoalRepo implements IGoalRepo {
  async getGoals(): Promise<Goal[] | LoadGoalsError> {
    try {
      const res = await container.resolve("authenticatedHttpClient").fetch(
        `${container.resolve("config").apiUrl}/api/goals`
      );
      if (!res.ok) {
        return new LoadGoalsError("Failed to load goals");
      }
      const data = (await res.json()) as { goals: Goal[] };
      return data.goals;
    } catch {
      return new LoadGoalsError("Failed to load goals");
    }
  }

  async createGoal(goal: Goal): Promise<void | CreateGoalError> {
    try {
      const res = await container.resolve("authenticatedHttpClient").fetch(
        `${container.resolve("config").apiUrl}/api/goals`,
        {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: goal.name }),
      });
      if (!res.ok) {
        return new CreateGoalError("Failed to create goal");
      }
    } catch {
      return new CreateGoalError("Failed to create goal");
    }
  }

  async deleteGoal(id: string): Promise<void | DeleteGoalError> {
    try {
      const res = await container.resolve("authenticatedHttpClient").fetch(
        `${container.resolve("config").apiUrl}/api/goals/${id}`,
        {
        method: "DELETE",
      });
      if (!res.ok) {
        return new DeleteGoalError("Failed to delete goal");
      }
    } catch {
      return new DeleteGoalError("Failed to delete goal");
    }
  }

  async updateGoal(id: string, name: string): Promise<void | UpdateGoalError> {
    try {
      const res = await container.resolve("authenticatedHttpClient").fetch(
        `${container.resolve("config").apiUrl}/api/goals/${id}`,
        {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name }),
      });
      if (!res.ok) {
        return new UpdateGoalError("Failed to update goal");
      }
    } catch {
      return new UpdateGoalError("Failed to update goal");
    }
  }
}
export { GoalRepo };
