import type { ToggleTaskError } from "../../core/errors/task-errors";
import { container } from "../../utils/container";

class ToggleTaskController {
  handleToggleTask(
    taskId: string,
    completed: boolean
  ): Promise<void | ToggleTaskError> {
    const taskRepo = container.resolve("taskRepo");
    return taskRepo.toggleTask(taskId, completed);
  }
}

export { ToggleTaskController };
