import { BehaviorSubject, Observable } from "../libs/rx";
import { container } from "../utils/container";
import type { AuthSignInLifecycle } from "./ports/AuthSignInLifecycle";
import {
  createGoogleSignInStrategy,
  type GoogleSignInStrategy,
} from "./googleSignInStrategy";
import {
  createAuthSessionProvider,
} from "./createAuthSessionProvider";
import type { AuthSession, IAuthSessionProvider } from "./ports/IAuthSessionProvider";
import type { IUnauthorizedHandler } from "./ports/IUnauthorizedHandler";

export type AuthStatus =
  | "loading"
  | "signedOut"
  | "checking"
  | "allowed"
  | "denied";

interface AuthState {
  status: AuthStatus;
  email: string | null;
  contactEmail: string | null;
}

const initialState: AuthState = {
  status: "loading",
  email: null,
  contactEmail: null,
};

export class AuthController implements AuthSignInLifecycle, IUnauthorizedHandler {
  private _state = new BehaviorSubject<AuthState>(initialState);
  private readonly signInStrategy: GoogleSignInStrategy;
  private readonly sessionProvider: IAuthSessionProvider;
  private checkedToken: string | null = null;

  constructor(
    signInStrategyFactory: (
      lifecycle: AuthSignInLifecycle
    ) => GoogleSignInStrategy = createGoogleSignInStrategy,
    sessionProviderFactory: () => IAuthSessionProvider = createAuthSessionProvider
  ) {
    this.signInStrategy = signInStrategyFactory(this);
    this.sessionProvider = sessionProviderFactory();
  }

  initialize(): void {
    this.signInStrategy.init();
    this.sessionProvider.initialize((session) => {
      void this.resolveSession(session);
    });
  }

  notifySignInResolving(): void {
    this.patchState({ status: "checking" });
  }

  notifySignInFailed(): void {
    this.patchState({ status: "signedOut" });
  }

  async signInWithGoogle(): Promise<void> {
    this.notifySignInResolving();
    await this.signInStrategy.signIn();
  }

  async signOut(): Promise<void> {
    await this.sessionProvider.signOut();
  }

  async handleUnauthorized(): Promise<void> {
    await this.signOut();
  }

  get state$(): Observable<AuthState> {
    return this._state.asObservable();
  }

  getState(): AuthState {
    return this._state.value;
  }

  private async resolveSession(session: AuthSession | null): Promise<void> {
    if (!session) {
      this.checkedToken = null;
      this.patchState({ status: "signedOut", email: null });
      return;
    }

    if (this.checkedToken === session.accessToken) return;
    this.checkedToken = session.accessToken;

    this.patchState({
      status: "checking",
      email: session.email,
    });

    const access = await this.fetchAccess(session.accessToken);
    if (!access) return;

    this.patchState({
      contactEmail: access.contactEmail,
      status: access.allowed ? "allowed" : "denied",
    });
  }

  private async fetchAccess(
    accessToken: string
  ): Promise<{ allowed: boolean; contactEmail: string } | null> {
    const res = await fetch(`${container.resolve("config").apiUrl}/api/auth/me`, {
      headers: { Authorization: `Bearer ${accessToken}` },
    });

    if (res.status === 401) {
      await this.sessionProvider.signOut();
      return null;
    }

    if (!res.ok) {
      return { allowed: false, contactEmail: "contact@example.com" };
    }

    return res.json();
  }

  private patchState(partial: Partial<AuthState>): void {
    this._state.next({ ...this._state.value, ...partial });
  }
}
