import { useEffect, useRef, useState } from "react";
import { Checkbox } from "radix-ui";
import { CheckIcon, Cross2Icon, ReloadIcon } from "@radix-ui/react-icons";
import type { Task } from "../../../../core/entities/Task";
import type { ListTasksController } from "../../../view-controllers/ListTasksController";
import formClasses from "../../components/form/form.module.css";
import buttonClasses from "../../components/button/button.module.css";
import { useControllerState } from "../../hooks/useControllerState";
import classes from "./goals.module.css";

interface Props {
  goalId: string;
  listTasksController: ListTasksController;
  onAddTask: (goalId: string, name: string) => Promise<void | Error>;
}

interface EditableTaskNameProps {
  task: Task;
  goalId: string;
  listTasksController: ListTasksController;
}

function EditableTaskName({
  task,
  goalId,
  listTasksController,
}: EditableTaskNameProps) {
  const nameRef = useRef<HTMLSpanElement>(null);

  useEffect(() => {
    if (
      nameRef.current &&
      document.activeElement !== nameRef.current
    ) {
      nameRef.current.textContent = task.name;
    }
  }, [task.name]);

  function handleBlur(event: React.FocusEvent<HTMLSpanElement>) {
    const rawText = event.currentTarget.textContent ?? "";
    const text = rawText.trim();

    if (!text) {
      event.currentTarget.textContent = task.name;
      listTasksController.cancelTaskRename(task.id);
      return;
    }

    listTasksController.scheduleTaskRename(goalId, task.id, rawText);
    listTasksController.flushTaskRename(task.id);
  }

  function handleKeyDown(event: React.KeyboardEvent<HTMLSpanElement>) {
    if (event.key === "Enter") {
      event.preventDefault();
      event.currentTarget.blur();
    }
  }

  function handlePaste(event: React.ClipboardEvent<HTMLSpanElement>) {
    event.preventDefault();
    const text = event.clipboardData.getData("text/plain");
    document.execCommand("insertText", false, text);
  }

  return (
    <span
      ref={nameRef}
      contentEditable
      suppressContentEditableWarning
      className={
        task.completed
          ? `${classes.TaskName} ${classes.TaskNameEditable} ${classes.TaskNameDone}`
          : `${classes.TaskName} ${classes.TaskNameEditable}`
      }
      onInput={(event) =>
        listTasksController.scheduleTaskRename(
          goalId,
          task.id,
          event.currentTarget.textContent ?? ""
        )
      }
      onBlur={handleBlur}
      onKeyDown={handleKeyDown}
      onPaste={handlePaste}
    />
  );
}

export function TaskList({
  goalId,
  listTasksController,
  onAddTask,
}: Props) {
  const { tasksByGoalId, savingIds, pendingIds } =
    useControllerState(listTasksController);
  const tasks = tasksByGoalId[goalId] ?? [];

  const [taskName, setTaskName] = useState("");
  const [submitting, setSubmitting] = useState(false);

  async function handleAddTask(event: React.FormEvent) {
    event.preventDefault();

    const name = taskName.trim();
    if (!name) {
      return;
    }

    setSubmitting(true);
    const result = await onAddTask(goalId, name);
    setSubmitting(false);

    if (!(result instanceof Error)) {
      setTaskName("");
    }
  }

  return (
    <div className={classes.TaskList}>
      {tasks.length === 0 ? (
        <p className={classes.EmptyTasks}>No objectives yet.</p>
      ) : (
        <ul className={classes.TaskItems}>
          {tasks.map((task) => {
            const isPending = pendingIds.has(task.id);
            const isSaving = savingIds.has(task.id);

            return (
              <li key={task.id} className={classes.TaskItem}>
                <Checkbox.Root
                  className={classes.TaskCheckbox}
                  checked={task.completed}
                  disabled={isPending}
                  onCheckedChange={() =>
                    listTasksController.toggleTask(
                      goalId,
                      task.id,
                      !task.completed
                    )
                  }
                >
                  <Checkbox.Indicator>
                    <CheckIcon />
                  </Checkbox.Indicator>
                </Checkbox.Root>
                <EditableTaskName
                  task={task}
                  goalId={goalId}
                  listTasksController={listTasksController}
                />
                {isSaving ? (
                  <ReloadIcon
                    className={`${classes.DeleteTaskButton} ${classes.Spinning}`}
                    aria-label="Saving objective"
                  />
                ) : (
                  <button
                    type="button"
                    aria-label="Delete task"
                    className={classes.DeleteTaskButton}
                    disabled={isPending}
                    onClick={() =>
                      listTasksController.deleteTask(goalId, task.id)
                    }
                  >
                    <Cross2Icon />
                  </button>
                )}
              </li>
            );
          })}
        </ul>
      )}
      <form className={classes.AddTaskForm} onSubmit={handleAddTask}>
        <input
          className={`${formClasses.Input} ${classes.AddTaskInput}`}
          type="text"
          placeholder="Add an objective..."
          value={taskName}
          onChange={(event) => setTaskName(event.target.value)}
        />
        <button
          type="submit"
          className={`${buttonClasses.Button} ${classes.AddTaskButton}`}
          disabled={submitting}
        >
          Add
        </button>
      </form>
    </div>
  );
}
