import type {
  AuthSession,
  IAuthSessionProvider,
} from "./ports/IAuthSessionProvider";
import { getSupabaseClient } from "./supabaseClient";

export class SupabaseAuthSessionProvider implements IAuthSessionProvider {
  initialize(onSessionChange: (session: AuthSession | null) => void): void {
    const supabase = getSupabaseClient();

    void supabase.auth.getSession().then(({ data }) => {
      onSessionChange(this.toAuthSession(data.session));
    });

    supabase.auth.onAuthStateChange((_event, session) => {
      onSessionChange(this.toAuthSession(session));
    });
  }

  async getAccessToken(): Promise<string | null> {
    const supabase = getSupabaseClient();
    const {
      data: { session },
    } = await supabase.auth.getSession();
    return session?.access_token ?? null;
  }

  async signInWithGoogle(): Promise<void> {
    throw new Error(
      "Use GoogleSignInStrategy.signIn() for Supabase Google OAuth"
    );
  }

  async signOut(): Promise<void> {
    await getSupabaseClient().auth.signOut();
  }

  private toAuthSession(
    session: { access_token: string; user: { email?: string | null } } | null
  ): AuthSession | null {
    if (!session) return null;
    return {
      accessToken: session.access_token,
      email: session.user.email ?? null,
    };
  }
}
