import { Capacitor } from "@capacitor/core";
import { createClient, type SupabaseClient } from "@supabase/supabase-js";
import { container } from "../utils/container";

let supabaseInstance: SupabaseClient | null = null;

export function getSupabaseClient(): SupabaseClient {
  if (supabaseInstance) return supabaseInstance;

  const config = container.resolve("config");
  const supabaseUrl = config.supabaseUrl;
  const supabasePublishableKey = config.supabasePublishableKey;

  if (!supabaseUrl || !supabasePublishableKey) {
    throw new Error(
      "Missing BUN_PUBLIC_SUPABASE_URL or BUN_PUBLIC_SUPABASE_PUBLISHABLE_KEY environment variables"
    );
  }

  const isNative = Capacitor.isNativePlatform();
  supabaseInstance = createClient(supabaseUrl, supabasePublishableKey, {
    auth: isNative
      ? {
          flowType: "pkce",
          detectSessionInUrl: false,
          persistSession: true,
        }
      : undefined,
  });

  return supabaseInstance;
}
