import type { DeleteGoalError } from "../../core/errors/goal-errors";
import { container } from "../../utils/container";

class DeleteGoalController {
  handleDeleteGoal(goalId: string): Promise<void | DeleteGoalError> {
    const goalRepo = container.resolve("goalRepo");
    return goalRepo.deleteGoal(goalId);
  }
}

export { DeleteGoalController };
