import {
  createContext,
  useContext,
  useEffect,
  useMemo,
} from "react";
import type { AuthStatus } from "./AuthController";
import { container } from "../utils/container";
import { useControllerState } from "../view/react/hooks/useControllerState";

export type { AuthStatus };

interface AuthContextValue {
  status: AuthStatus;
  email: string | null;
  contactEmail: string | null;
  signInWithGoogle: () => Promise<void>;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextValue | null>(null);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const authController = container.resolve("authController");
  const { status, email, contactEmail } = useControllerState(authController);

  useEffect(() => {
    authController.initialize();
  }, [authController]);

  const value = useMemo<AuthContextValue>(
    () => ({
      status,
      email,
      contactEmail,
      signInWithGoogle: () => authController.signInWithGoogle(),
      signOut: () => authController.signOut(),
    }),
    [authController, status, email, contactEmail]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth(): AuthContextValue {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}
