import { createServer, Model } from "miragejs";

export function startMockServer() {
  createServer({
    models: {
      goal: Model,
      task: Model,
    },

    seeds(server) {
      const goal1 = server.create("goal", {
        name: "Reach level 10 in TypeScript",
      });
      const goal2 = server.create("goal", {
        name: "Complete the dungeon of clean architecture",
      });
      server.create("goal", { name: "Defeat the bug dragon" });
      server.create("goal", { name: "Unlock the artifact of test coverage" });

      server.create("task", {
        goalId: goal1.id,
        name: "Learn generics",
        completed: true,
      });
      server.create("task", {
        goalId: goal1.id,
        name: "Practice utility types",
        completed: false,
      });
      server.create("task", {
        goalId: goal2.id,
        name: "Split use cases into controllers",
        completed: false,
      });
    },

    routes() {
      this.namespace = "api";

      this.get("/auth/me", () => {
        return { allowed: true, contactEmail: "contact@example.com" };
      });

      this.get("/goals", (schema) => {
        const goals = schema.goals.all().models.map((goal) => {
          const tasks = schema.tasks
            .all()
            .models.filter((task) => task.goalId === goal.id);

          return {
            ...goal.attrs,
            totalTasks: tasks.length,
            completedTasks: tasks.filter((task) => task.completed).length,
          };
        });

        return { goals };
      });

      this.post("/goals", (schema, request) => {
        const attrs = JSON.parse(request.requestBody);
        return schema.goals.create({ name: attrs.name });
      });

      this.delete("/goals/:id", (schema, request) => {
        const goal = schema.goals.find(request.params.id);
        goal?.destroy();
        return new Response(null, { status: 204 });
      });

      this.patch("/goals/:id", (schema, request) => {
        const goal = schema.goals.find(request.params.id);
        const attrs = JSON.parse(request.requestBody);
        goal?.update({ name: attrs.name });
        return new Response(null, { status: 204 });
      });

      this.get("/goals/:goalId/tasks", (schema, request) => {
        const tasks = schema.tasks
          .all()
          .models.filter((task) => task.goalId === request.params.goalId);
        return { tasks };
      });

      this.post("/goals/:goalId/tasks", (schema, request) => {
        const attrs = JSON.parse(request.requestBody);
        return schema.tasks.create({
          goalId: request.params.goalId,
          name: attrs.name,
          completed: false,
        });
      });

      this.patch("/tasks/:id", (schema, request) => {
        const task = schema.tasks.find(request.params.id);
        const attrs = JSON.parse(request.requestBody);
        const updates: { completed?: boolean; name?: string } = {};

        if (typeof attrs.completed === "boolean") {
          updates.completed = attrs.completed;
        }

        if (typeof attrs.name === "string") {
          updates.name = attrs.name;
        }

        task?.update(updates);
        return new Response(null, { status: 204 });
      });

      this.delete("/tasks/:id", (schema, request) => {
        const task = schema.tasks.find(request.params.id);
        task?.destroy();
        return new Response(null, { status: 204 });
      });
    },
  });
}
